import java.nio.file.*;import java.util.*;import java.security.*;public class TsvRoundTrip{static String hex(byte[]b){StringBuilder s=new StringBuilder();for(byte x:b)s.append(String.format("%02x",x));return s.toString();}public static void main(String[]a)throws Exception{Path p=Paths.get(a.length>0?a[0]:"data/events.tsv");String raw=Files.readString(p).replace("\r\n","\n").strip()+"\n";List<String>lines=Arrays.asList(raw.split("\n"));if(lines.size()<2)throw new RuntimeException("empty TSV");String[]head=lines.get(0).split("\t",-1);String[]req={"title","shortTitle","category","lane","sub","start","endKnown","endInferred","href","timeZone","timeZoneLabel","isFixedTimeZone","status","source"};if(!Arrays.equals(head,req))throw new RuntimeException("header mismatch");int cols=head.length;for(int i=1;i<lines.size();i++){String[]c=lines.get(i).split("\t",-1);if(c.length!=cols)throw new RuntimeException("column mismatch line "+(i+1)+" got "+c.length+" expected "+cols);if(c[0].isBlank()||c[5].isBlank())throw new RuntimeException("missing title/start line "+(i+1));}MessageDigest md=MessageDigest.getInstance("SHA-256");System.out.println("Java TSV structural comparison OK: "+(lines.size()-1)+" events, "+cols+" columns");System.out.println("SHA256 "+hex(md.digest(raw.getBytes("UTF-8"))));}}
